import asyncio
import websockets
import json
import uuid
from collections import defaultdict
from typing import Dict, Set, List, Optional
from dataclasses import dataclass
from datetime import datetime

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str
    created_at: datetime

@dataclass
class Player:
    id: str
    username: str
    inventory: Dict[str, int]  # item_id -> quantity
    connected: bool = False

class MMOGameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.player_connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.trade_locks: Dict[str, asyncio.Lock] = {}
        self.item_ownership_lock = asyncio.Lock()
        
    async def register_player(self, player_id: str, username: str):
        if player_id not in self.players:
            self.players[player_id] = Player(player_id, username, {})
            self.trade_locks[player_id] = asyncio.Lock()
            print(f"Player {username} registered")
    
    async def handle_message(self, websocket, message: str):
        try:
            data = json.loads(message)
            msg_type = data.get('type')
            
            if msg_type == 'login':
                await self.handle_login(websocket, data)
            elif msg_type == 'trade_request':
                await self.handle_trade_request(data)
            elif msg_type == 'trade_accept':
                await self.handle_trade_accept(data)
            elif msg_type == 'trade_cancel':
                await self.handle_trade_cancel(data)
            elif msg_type == 'get_inventory':
                await self.handle_get_inventory(websocket, data)
            elif msg_type == 'transfer_item':
                await self.handle_transfer_item(websocket, data)
                
        except json.JSONDecodeError:
            await websocket.send(json.dumps({'error': 'Invalid JSON'}))
        except Exception as e:
            print(f"Error handling message: {e}")
            await websocket.send(json.dumps({'error': 'Internal server error'}))
    
    async def handle_login(self, websocket, data: dict):
        player_id = data.get('player_id')
        username = data.get('username')
        
        if not player_id or not username:
            await websocket.send(json.dumps({'error': 'Missing player_id or username'}))
            return
            
        await self.register_player(player_id, username)
        self.player_connections[player_id] = websocket
        await websocket.send(json.dumps({'status': 'connected', 'player_id': player_id}))
        
        # Send initial inventory
        player = self.players[player_id]
        player.connected = True
        await self.send_inventory_update(player_id)
    
    async def handle_get_inventory(self, websocket, data: dict):
        player_id = data.get('player_id')
        if player_id and player_id in self.players:
            await self.send_inventory_update(player_id)
    
    async def handle_transfer_item(self, websocket, data: dict):
        player_id = data.get('player_id')
        item_id = data.get('item_id')
        target_player_id = data.get('target_player_id')
        quantity = data.get('quantity', 1)
        
        if not all([player_id, item_id, target_player_id]):
            await websocket.send(json.dumps({'error': 'Missing required fields'}))
            return
            
        if player_id not in self.players or target_player_id not in self.players:
            await websocket.send(json.dumps({'error': 'Player not found'}))
            return
            
        if item_id not in self.items:
            await websocket.send(json.dumps({'error': 'Item not found'}))
            return
            
        # Validate item ownership
        item = self.items[item_id]
        if item.owner_id != player_id:
            await websocket.send(json.dumps({'error': 'Item not owned by player'}))
            return
            
        if quantity <= 0:
            await websocket.send(json.dumps({'error': 'Invalid quantity'}))
            return
            
        # Check if player has enough items
        if player_id not in self.players or self.players[player_id].inventory.get(item_id, 0) < quantity:
            await websocket.send(json.dumps({'error': 'Not enough items'}))
            return
            
        # Use lock to prevent race conditions during transfer
        async with self.item_ownership_lock:
            # Validate again after lock
            if self.players[player_id].inventory.get(item_id, 0) < quantity:
                await websocket.send(json.dumps({'error': 'Not enough items'}))
                return
                
            # Perform transfer
            await self.execute_item_transfer(player_id, target_player_id, item_id, quantity)
            
            # Send updates to both players
            await self.send_inventory_update(player_id)
            if target_player_id in self.player_connections:
                await self.send_inventory_update(target_player_id)
            
            await websocket.send(json.dumps({'status': 'success', 'message': 'Item transferred'}))
    
    async def execute_item_transfer(self, from_player_id: str, to_player_id: str, item_id: str, quantity: int):
        # Update from player's inventory
        if from_player_id in self.players:
            if item_id in self.players[from_player_id].inventory:
                self.players[from_player_id].inventory[item_id] -= quantity
                if self.players[from_player_id].inventory[item_id] <= 0:
                    del self.players[from_player_id].inventory[item_id]
        
        # Update to player's inventory
        if to_player_id in self.players:
            if item_id not in self.players[to_player_id].inventory:
                self.players[to_player_id].inventory[item_id] = 0
            self.players[to_player_id].inventory[item_id] += quantity
        
        # Update item ownership
        if item_id in self.items:
            self.items[item_id].owner_id = to_player_id
    
    async def send_inventory_update(self, player_id: str):
        if player_id in self.players and player_id in self.player_connections:
            player = self.players[player_id]
            inventory_data = []
            for item_id, quantity in player.inventory.items():
                if item_id in self.items:
                    item = self.items[item_id]
                    inventory_data.append({
                        'id': item.id,
                        'name': item.name,
                        'type': item.type,
                        'value': item.value,
                        'quantity': quantity,
                        'owner_id': item.owner_id
                    })
            
            await self.player_connections[player_id].send(
                json.dumps({
                    'type': 'inventory_update',
                    'player_id': player_id,
                    'inventory': inventory_data
                })
            )
    
